select p.user_id
from t_order_withdraw p


        and p.channel_id = #{channelId}


        and p.currency_id=#{currencyId}

    and p.order_status = 4

        and p.withdraw_time BETWEEN #{startTime} AND #{endTime}

select
ifnull(sum(a.amount), 0.0000) as amount
, ifnull(sum(a.fee), 0.0000) as fee
, ifnull(sum(a.real_amount), 0.0000) as realAmount
from t_order_withdraw a
left join t_user u on u.user_id = a.user_id

    and a.merchant_code = #{merchantCode}
    and a.merchant_id = #{merchantId}
    and a.pay_channel_id = #{payChannelId}
    and a.pay_type_id = #{payTypeId}

    and a.type = #{type}
    and a.order_no = #{orderNo}
    and a.currency_id = #{currencyId}
    and a.item_id = #{itemId}
    and a.chain_tag = #{chainTag}
    and a.item_name = #{itemName}
    and a.tx_id = #{txId}
    and a.user_id = #{userId}
    and a.tg_user_id = #{tgUserId}
    and a.shareholder_id = #{shareholderId}
    and a.channel_id = #{channelId}
    and u.user_tg_username like concat('%', #{username}, '%')

    and a.amount = #{amount}
    and a.exchange_type = #{exchangeType}
    and a.fee = #{fee}
    and a.real_amount = #{realAmount}
    AND a.to_addr LIKE CONCAT('%', #{toAddr}, '%')
    and a.from_addr = #{fromAddr}
    and a.order_status = #{orderStatus}
    and screen_shot = #{screenShot}
    and a.up_order_no = #{upOrderNo}
    and a.up_order_info = #{upOrderInfo}
    and a.up_notify_info = #{upNotifyInfo}
    and a.sign_time = #{signTime}
    and a.sign = #{sign}
    and (


                a.withdraw_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )


    and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )


        and a.channel_id IN

            #{item}

select
    a.merchant_id as merchantId,
    u.name as merchantName,
    count(distinct a.user_id) as peopleNum,
    count(*) as orderNum,
    sum(case when a.order_status = 4 then 1 else 0 end) as successOrderNum,
    ifnull(sum(a.amount), 0.0000) as amount,
    ifnull(sum(case when a.order_status = 4 then a.amount else 0 end), 0.0000) as successAmount,
    case
    when count(*) = 0 then 0
    else round(sum(case when a.order_status = 4 then 1 else 0 end) * 100.0 / count(*), 2)
    end as successRate
from t_order_withdraw a
left join t_merchant_pay u on u.id = a.merchant_id

    and a.merchant_id = #{merchantId}
    and a.pay_channel_id = #{payChannelId}
    and a.pay_type_id = #{payTypeId}
    and a.currency_id = #{currencyId}
    and (


                a.withdraw_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )


    and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )



group by a.merchant_id

select
a.pay_channel_id as payChannelId,
u.name as payChannelName,
count(distinct a.user_id) as peopleNum,
count(*) as orderNum,
sum(case when a.order_status = 4 then 1 else 0 end) as successOrderNum,
